import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { spawnSync } from "node:child_process";
import { randomBytes } from "node:crypto";
import path from "node:path";

type Check = {
	name: string;
	ok: boolean;
	detail: string;
};

type Facts = {
