function createIssue(args: {
	owner: string;
	repository: string;
	title: string;
	body: string;
}) {
	const result = run("gh", [
		"issue",
		"create",
		"--repo",
		`${args.owner}/${args.repository}`,
		"--title",
		args.title,
		"--body",
		args.body,
	]);
	if (result.status !== 0) {
		return {
			ok: false as const,
			number: null as number | null,
			url: null as string | null,
			error: summarizeCommandResult(result),
		};
	}

	const parsedIssue = parseIssueCreateUrl(result.stdout);
	if (!parsedIssue.ok) {
		return {
			ok: false as const,
			number: null,
			url: null,
			error: parsedIssue.error,
		};
	}

	return {
		ok: true as const,
		number: parsedIssue.issueNumber,
		url: parsedIssue.issueUrl,
		error: null as string | null,
	};
}

function addIssueToProject(args: {
	projectNumber: number;
	owner: string;
	issueUrl: string;
}) {
	const result = run("gh", [
		"project",
		"item-add",
		String(args.projectNumber),
		"--owner",
		args.owner,
		"--url",
		args.issueUrl,
		"--format",
		"json",
	]);
	if (result.status !== 0) {
		return {
			ok: false as const,
			itemId: null as string | null,
			error: summarizeCommandResult(result),
		};
	}
	try {
		const parsed = JSON.parse(result.stdout) as {
			id?: string;
			items?: Array<{ id?: string }>;
		};
		return {
			ok: true as const,
			itemId:
				parsed.id ??
				(parsed.items?.[0]?.id ? (parsed.items?.[0]?.id ?? null) : null),
			error: null as string | null,
		};
	} catch {
		return {
			ok: true as const,
			itemId: null as string | null,
			error: null as string | null,
		};
	}
}

