		} as ParsedArgs;
	}

	if (flags.length === 1 && flags[0] === "--dry-run") {
		return {
			mode: "dry-run",
		} as ParsedArgs;
	}

	if (
		flags.length === 4 &&
		flags[0] === "--apply" &&
		flags[1] === "--yes" &&
		flags[2] === "--project-title" &&
		flags[3].trim().length > 0
	) {
		return {
			mode: "apply",
			projectTitle: flags[3],
		} as ParsedArgs;
	}

	if (
		flags.length === 3 &&
		flags[0] === "--apply" &&
		flags[1] === "--yes" &&
		flags[2] === "--create-status-field"
	) {
		return {
			mode: "apply",
			createStatusField: true,
		} as ParsedArgs;
	}

	return null;
}

function createGithubProject(owner: string, title: string) {
	const result = run("gh", [
		"project",
		"create",
		"--owner",
		owner,
		"--title",
		title,
		"--format",
		"json",
	]);

	if (result.status !== 0) {
		return {
			ok: false as const,
			attempted: true,
			project: {
				title,
				id: null as string | null,
				number: null as number | null,
				url: null as string | null,
			},
			errorSummary:
				(result.stderr || result.stdout || result.error?.message || "failed")
					.toString()
					.trim() || "gh project create failed",
