	}

	try {
		const parsed = JSON.parse(result.stdout) as {
			id?: string;
			title?: string;
			number?: number;
			url?: string;
		};

		return {
			ok: true as const,
			attempted: true,
			project: {
				title: parsed.title ?? title,
				id: parsed.id ?? null,
				number: parsed.number ?? null,
				url: parsed.url ?? null,
